// [FEE-LOGIC] — {id} — hover
const el = document.querySelector('[data-af-id="{id}"]');
el.addEventListener('mouseenter', () => gsap.to(el, { boxShadow: '0 0 0 2px #8cc63f', duration: 0.2 }));
el.addEventListener('mouseleave', () => gsap.to(el, { boxShadow: 'none', duration: 0.3 }));

// [FEE-LOGIC] — {id} — scroll
gsap.to('[data-af-id="{id}"]', {
  yPercent: -30,
  ease: 'none',
  scrollTrigger: { trigger: '[data-af-id="{id}"]', start: 'top bottom', end: 'bottom top', scrub: true }
});

// [FEE-LOGIC] — {id} — scroll
gsap.from('[data-af-id="{id}"]', {
  opacity: 0, y: 50,
  scrollTrigger: { trigger: '[data-af-id="{id}"]', start: 'top 80%', toggleActions: 'play none none reverse' }
});
